-- QUERY MEJORADA
SELECT
a.id_alo, 
a.Alo_NotasXML,
x.y.value('(texto)[1]', 'char(50)') Nota,
x.y.value('@web', 'char(50)') Web,
x.y.value('@voucher', 'char(50)') Voucher,
x.y.value('(Contratos)[1]', 'char(50)') contrato,
x.y.value('@inicio', 'char(50)') FechaInicio,
x.y.value('@fin', 'char(50)') FechaFin


FROM Tbl_Alojamiento a
CROSS APPLY a.Alo_NotasXML.nodes('notas/nota') AS x(y)

WHERE 1=1
AND a.Id_Alo IN (40040,39139,25219,39655,40001,39469,13020,23513,40380,40385,39468,39336,39966,39138,13400,21608,40094,39864,39168,39135,41774,39466,41282,15003,39171,40010,39222,37445,41562,39226,40155,40752,20794,22829,39133,39167,39132,13744,39337,39332,39155,13302,39874,39166,13873,39172,40000,40322,39223,39328,39889,39477,40324,39165,39327,39164,39656,39657,39659,40277,39153,41568,38283,28394,39240,38279,39479,40530,39470,39842,41685,38679,41563,41565,40007,38334,39921,39239,40534,39480,39324,24829,39238,39660,23223,40017,39175,39482,39483,22155,39481,39923,39484,39145,39924,39487,38282,40011,39929,40079,16190,39996,38281,39847,39237,39236,39162,21264,38278,41561,39235,39667,41174,39476,40522,38675,40524,38677,38678,39234,41807,38716,38277,39233,40090,38280,38701,38691,40531,40532,39474,39879,35237,39541,40009,40387,39169,39486,39485,39475,39665,39231,39925,39170,17928,39852)
--AND x.y.value('(Contratos)[1]', 'char(50)') is not null
--AND x.y.value('@web', 'char(50)') = 'True'
--AND x.y.value('@voucher', 'char(50)') = 'True'


SELECT Alo_NotasXML FROM Tbl_Alojamiento WHERE ID_Alo = 40385

